//! Hope Jar — The Information Battery for FOIL
//!
//! The inverse of Pandora's Box. You fill it instead of emptying it.
//! A sealed 196884-key cache that charges once from standing wave entropy
//! and discharges predictions forever. Once sealed, the jar never reopens.
//! The Monster Group's symmetry operations permute the keys without consuming them.
//!
//!
//! Charge: one rain recording -> 170 seeds -> Monster expansion -> 196884 keys
//! Discharge: 16407 keys per aeon tick, 5469 per lane, 6.25 ticks/s
//! Break-even: ~26 minutes at 1% hit rate (pays for itself during one replay)
//!
//! Lean: `Gnosis.HopeJar`

use crate::rf_physics_cpu::MONSTER_VECTOR_FLOOR;

const AEON_PHASES: usize = 12;
const FOIL_LANES: usize = 3;
const CARRIERS_PER_SLOT: usize = MONSTER_VECTOR_FLOOR as usize / (AEON_PHASES * FOIL_LANES);
const FIBONACCI_HASH: u64 = 11_400_714_819_323_198_485;

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum BoxState {
    Empty,
    Charging,
    Sealed,
}

#[derive(Clone, Debug)]
pub struct HopeJar {
    keys: Vec<u64>,
    state: BoxState,
    seeds_loaded: usize,
    charge_cost_us: u64,
    total_discharges: u64,
}

impl Default for HopeJar {
    fn default() -> Self {
        Self::new()
    }
}

impl HopeJar {
    pub fn new() -> Self {
        Self {
            keys: vec![0u64; MONSTER_VECTOR_FLOOR as usize],
            state: BoxState::Empty,
            seeds_loaded: 0,
            charge_cost_us: 0,
            total_discharges: 0,
        }
    }

    pub fn state(&self) -> BoxState {
        self.state
    }

    pub fn seeds_loaded(&self) -> usize {
        self.seeds_loaded
    }

    pub fn total_discharges(&self) -> u64 {
        self.total_discharges
    }

    pub fn charge_from_seeds(&mut self, seeds: &[u64], analysis_time_us: u64) {
        if self.state == BoxState::Sealed {
            return;
        }
        self.state = BoxState::Charging;
        self.charge_cost_us += analysis_time_us;

        for &seed in seeds {
            if self.seeds_loaded >= MONSTER_VECTOR_FLOOR as usize {
                break;
            }
            let base_idx = self.seeds_loaded;
            self.keys[base_idx] = seed;
            self.seeds_loaded += 1;

            let expansion_count = (MONSTER_VECTOR_FLOOR as usize - self.seeds_loaded)
                .min(CARRIERS_PER_SLOT.saturating_sub(1));
            for k in 0..expansion_count {
                if self.seeds_loaded >= MONSTER_VECTOR_FLOOR as usize {
                    break;
                }
                let expanded = seed
                    .wrapping_mul(FIBONACCI_HASH)
                    .wrapping_add(k as u64)
                    .wrapping_mul(FIBONACCI_HASH);
                self.keys[self.seeds_loaded] = expanded;
                self.seeds_loaded += 1;
            }
        }

        if self.seeds_loaded >= MONSTER_VECTOR_FLOOR as usize {
            self.state = BoxState::Sealed;
        }
    }

    pub fn is_sealed(&self) -> bool {
        self.state == BoxState::Sealed
    }

    pub fn discharge(&mut self, aeon_phase: u8, lane: u8) -> &[u64] {
        if self.state != BoxState::Sealed {
            return &[];
        }
        self.total_discharges += 1;
        let phase = (aeon_phase % AEON_PHASES as u8) as usize;
        let lane_idx = (lane % FOIL_LANES as u8) as usize;
        let slot = phase * FOIL_LANES + lane_idx;
        let start = slot * CARRIERS_PER_SLOT;
        let end = (start + CARRIERS_PER_SLOT).min(MONSTER_VECTOR_FLOOR as usize);
        &self.keys[start..end]
    }

    pub fn discharge_all_lanes(&mut self, aeon_phase: u8) -> [&[u64]; 3] {
        if self.state != BoxState::Sealed {
            return [&[], &[], &[]];
        }
        self.total_discharges += 3;
        let phase = (aeon_phase % AEON_PHASES as u8) as usize;
        let base = phase * FOIL_LANES * CARRIERS_PER_SLOT;
        let s1 = base;
        let s2 = base + CARRIERS_PER_SLOT;
        let s3 = base + 2 * CARRIERS_PER_SLOT;
        let e3 = (s3 + CARRIERS_PER_SLOT).min(MONSTER_VECTOR_FLOOR as usize);
        [
            &self.keys[s1..s1 + CARRIERS_PER_SLOT],
            &self.keys[s2..s2 + CARRIERS_PER_SLOT],
            &self.keys[s3..e3],
        ]
    }

    pub fn telemetry(&self) -> HopeJarTelemetry {
        HopeJarTelemetry {
            state: self.state,
            seeds_loaded: self.seeds_loaded,
            capacity: MONSTER_VECTOR_FLOOR as usize,
            fill_pct: if MONSTER_VECTOR_FLOOR > 0 {
                (self.seeds_loaded as f64 / MONSTER_VECTOR_FLOOR as f64 * 100.0) as u8
            } else {
                0
            },
            charge_cost_us: self.charge_cost_us,
            total_discharges: self.total_discharges,
            keys_per_tick: CARRIERS_PER_SLOT * FOIL_LANES,
            keys_per_lane: CARRIERS_PER_SLOT,
        }
    }
}

#[derive(Clone, Debug)]
pub struct HopeJarTelemetry {
    pub state: BoxState,
    pub seeds_loaded: usize,
    pub capacity: usize,
    pub fill_pct: u8,
    pub charge_cost_us: u64,
    pub total_discharges: u64,
    pub keys_per_tick: usize,
    pub keys_per_lane: usize,
}

/// Encode the Hope Jar as a compact rknot-compatible binary.
/// Only stores the seeds (not the expanded keys) — the Monster
/// expansion is deterministic and can be replayed on any node.
///
/// Wire format: [HOPE][version:u8][seed_count:u16be][seeds:u64le*N][analysis_us:u64le]
/// Total size for rain.m4a: 4 + 1 + 2 + 170*8 + 8 = 1375 bytes.
impl HopeJar {
    pub fn encode_seeds(&self) -> Vec<u8> {
        let mut buf = Vec::with_capacity(4 + 1 + 2 + self.seeds_loaded * 8 + 8);
        buf.extend_from_slice(b"HOPE");
        buf.push(1); // version
        buf.extend_from_slice(&(self.seeds_loaded.min(u16::MAX as usize) as u16).to_be_bytes());
        // Write only the first `chargeThreshold` keys (the original seeds before expansion)
        let seed_count = self.seeds_loaded.min(MONSTER_VECTOR_FLOOR as usize);
        for i in 0..seed_count {
            buf.extend_from_slice(&self.keys[i].to_le_bytes());
        }
        buf.extend_from_slice(&self.charge_cost_us.to_le_bytes());
        buf
    }

    pub fn decode_seeds(data: &[u8]) -> Option<Self> {
        if data.len() < 7 || &data[0..4] != b"HOPE" || data[4] != 1 {
            return None;
        }
        let seed_count = u16::from_be_bytes([data[5], data[6]]) as usize;
        let expected = 7 + seed_count * 8 + 8;
        if data.len() < expected {
            return None;
        }
        let mut jar = Self::new();
        let mut seeds = Vec::with_capacity(seed_count);
        for i in 0..seed_count {
            let offset = 7 + i * 8;
            let key = u64::from_le_bytes([
                data[offset],
                data[offset + 1],
                data[offset + 2],
                data[offset + 3],
                data[offset + 4],
                data[offset + 5],
                data[offset + 6],
                data[offset + 7],
            ]);
            seeds.push(key);
        }
        let cost_offset = 7 + seed_count * 8;
        let cost = u64::from_le_bytes([
            data[cost_offset],
            data[cost_offset + 1],
            data[cost_offset + 2],
            data[cost_offset + 3],
            data[cost_offset + 4],
            data[cost_offset + 5],
            data[cost_offset + 6],
            data[cost_offset + 7],
        ]);
        jar.charge_from_seeds(&seeds, cost);
        Some(jar)
    }
}

// ═══════════════════════════════════════════════════════════════════
// HOPE JAR SIDECAR SCALER — adaptive Reynolds-gated entropy fleet
//
// Scales the number of active Hope Jar sidecars based on:
// 1. Computation intensity (EMA vs Reynolds threshold)
// 2. CPU capacity (available cores)
// 3. Entropy demand (unfilled prediction slots)
//
// Below Reynolds: 0 sidecars (laminar, no overhead)
// Above Reynolds: scale up until saturated
// ═══════════════════════════════════════════════════════════════════

const REYNOLDS_NS: u64 = 10_000;
const TURBULENT_NS: u64 = 100_000;
const KEYS_PER_SIDECAR_TICK: usize = 16407; // per aeon tick

pub struct HopeJarScaler {
    jars: Vec<HopeJar>,
    max_sidecars: usize,
    active_sidecars: usize,
    demand_keys: usize,
    total_ticks: u64,
}

impl HopeJarScaler {
    pub fn new(template: &HopeJar, max_sidecars: usize) -> Self {
        Self {
            jars: (0..max_sidecars).map(|_| template.clone()).collect(),
            max_sidecars,
            active_sidecars: 0,
            demand_keys: 0,
            total_ticks: 0,
        }
    }

    pub fn scale(&mut self, ema_ns: u64, demand_keys: usize) {
        self.demand_keys = demand_keys;

        if ema_ns < REYNOLDS_NS {
            self.active_sidecars = 0;
            return;
        }

        let intensity_ratio = (ema_ns / REYNOLDS_NS) as usize;
        let demand_sidecars = if KEYS_PER_SIDECAR_TICK > 0 {
            demand_keys.div_ceil(KEYS_PER_SIDECAR_TICK)
        } else {
            0
        };

        self.active_sidecars = intensity_ratio
            .min(demand_sidecars)
            .min(self.max_sidecars)
            .max(1);
    }

    /// CERTIFIED Reynolds-gated scale — size the sidecar fleet from the
    /// cert-attested computation cost instead of the runtime EMA.
    ///
    /// The EMA `scale` above is a YELLOW-probe: it sizes the fleet off a smoothed
    /// average, which LAGS a workload transition. After a heavy burst the EMA
    /// stays high, so `scale` keeps spinning sidecars through the laminar window
    /// (cheap work paying turbulent overhead) until the average decays below the
    /// Reynolds number — the same lag FOIL's entropy gate had. The certified
    /// computation cost is known per-tick (the admission cert), so this decides
    /// with ZERO lag and zero cold-start optimism.
    ///
    /// It also completes the laminar/turbulent model the EMA path left open: at
    /// or above `TURBULENT_NS` the fleet SATURATES to the demand-bounded maximum
    /// ("Above Reynolds: scale up until saturated"). Mirrors gnosis-frf
    /// `value_door::certified_light`; Lean
    /// `Gnosis.ValueDoorStoplight.certified_never_yellow` (zero axioms).
    pub fn scale_certified(&mut self, certified_cost_ns: u64, demand_keys: usize) {
        self.demand_keys = demand_keys;

        // RED / laminar: below the Reynolds number, no sidecars, no overhead.
        if certified_cost_ns < REYNOLDS_NS {
            self.active_sidecars = 0;
            return;
        }

        let demand_sidecars = if KEYS_PER_SIDECAR_TICK > 0 {
            demand_keys.div_ceil(KEYS_PER_SIDECAR_TICK)
        } else {
            0
        };

        // GREEN / fully turbulent: at or above the turbulent ceiling, saturate to
        // the demand-bounded maximum (the saturation the EMA path left unwired).
        if certified_cost_ns >= TURBULENT_NS {
            self.active_sidecars = demand_sidecars.min(self.max_sidecars).max(1);
            return;
        }

        // Transitional: scale linearly with intensity, bounded by demand and capacity.
        let intensity_ratio = (certified_cost_ns / REYNOLDS_NS) as usize;
        self.active_sidecars = intensity_ratio
            .min(demand_sidecars)
            .min(self.max_sidecars)
            .max(1);
    }

    pub fn active_sidecars(&self) -> usize {
        self.active_sidecars
    }

    pub fn tick(&mut self, aeon_phase: u8) -> Vec<Vec<u64>> {
        self.total_ticks += 1;
        let mut all_keys = Vec::new();
        for i in 0..self.active_sidecars {
            for lane in 0..3u8 {
                let keys = self.jars[i].discharge(aeon_phase, lane);
                if !keys.is_empty() {
                    all_keys.push(keys.to_vec());
                }
            }
        }
        all_keys
    }

    pub fn total_keys_per_tick(&self) -> usize {
        self.active_sidecars * KEYS_PER_SIDECAR_TICK
    }

    pub fn telemetry(&self) -> HopeJarScalerTelemetry {
        HopeJarScalerTelemetry {
            max_sidecars: self.max_sidecars,
            active_sidecars: self.active_sidecars,
            keys_per_tick: self.total_keys_per_tick(),
            demand_keys: self.demand_keys,
            total_ticks: self.total_ticks,
        }
    }
}

#[derive(Clone, Debug)]
pub struct HopeJarScalerTelemetry {
    pub max_sidecars: usize,
    pub active_sidecars: usize,
    pub keys_per_tick: usize,
    pub demand_keys: usize,
    pub total_ticks: u64,
}

impl std::fmt::Display for HopeJarScalerTelemetry {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(
            f,
            "HopeJarScaler[{}/{}] {}/tick demand={} ticks={}",
            self.active_sidecars,
            self.max_sidecars,
            self.keys_per_tick,
            self.demand_keys,
            self.total_ticks,
        )
    }
}

impl std::fmt::Display for HopeJarTelemetry {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        write!(
            f,
            "HopeJar[{:?}] {}/{} ({}%) | cost={}us | discharges={} | {}/tick {}/lane",
            self.state,
            self.seeds_loaded,
            self.capacity,
            self.fill_pct,
            self.charge_cost_us,
            self.total_discharges,
            self.keys_per_tick,
            self.keys_per_lane,
        )
    }
}

#[cfg(test)]
mod scaler_certified_tests {
    use super::*;

    /// The certified scaler is a pure Reynolds gate on the cert cost: laminar
    /// (0 sidecars) below the Reynolds number, scaled in the transitional band,
    /// saturated at/above the turbulent ceiling — no EMA read, so no lag and no
    /// cold-start. Operational form of the zero-axiom Lean
    /// `ValueDoorStoplight.certified_never_yellow`.
    #[test]
    fn certified_scale_is_pure_reynolds_gate() {
        let jar = HopeJar::new();
        let mut scaler = HopeJarScaler::new(&jar, 16);
        // Demand high enough to need every sidecar: > max_sidecars * KEYS_PER_SIDECAR_TICK.
        let demand = 17 * KEYS_PER_SIDECAR_TICK;

        // RED / laminar: below Reynolds -> zero sidecars.
        scaler.scale_certified(REYNOLDS_NS - 1, demand);
        assert_eq!(scaler.active_sidecars(), 0);

        // Transitional: just above Reynolds -> at least one sidecar.
        scaler.scale_certified(REYNOLDS_NS, demand);
        assert!(scaler.active_sidecars() >= 1);

        // GREEN / fully turbulent: at/above the ceiling -> saturate to capacity
        // (exercises the previously-dead TURBULENT_NS).
        scaler.scale_certified(TURBULENT_NS, demand);
        assert_eq!(scaler.active_sidecars(), 16);
        scaler.scale_certified(TURBULENT_NS * 100, demand);
        assert_eq!(scaler.active_sidecars(), 16);

        // Demand-bounded: the turbulent ceiling never spins more sidecars than
        // the demand needs (200k keys -> 13 sidecars, not the full 16).
        scaler.scale_certified(TURBULENT_NS, 200_000);
        assert_eq!(scaler.active_sidecars(), 13);
    }

    /// Measures the lag the cert removes. Replays the production EMA recurrence
    /// locally (deterministic) over a heavy->cheap workload transition and feeds
    /// each scaler the value its gate would see. The EMA scaler keeps the fleet
    /// spun up through the laminar window while its smoothed average decays; the
    /// certified scaler, fed the true cheap cost, drops to zero immediately.
    #[test]
    fn certified_scale_removes_ema_transition_lag() {
        let jar = HopeJar::new();
        let mut ema_scaler = HopeJarScaler::new(&jar, 16);
        let mut cert_scaler = HopeJarScaler::new(&jar, 16);
        let demand = 200_000usize;

        let heavy = 5 * REYNOLDS_NS; // 50us
        let cheap = REYNOLDS_NS / 100; // 100ns — laminar
        let ema_step = |ema: u64, cost: u64| {
            if ema == 0 {
                cost
            } else {
                (ema * 9 + cost) / 10
            }
        };

        // Warm the EMA on heavy work, then switch the workload to cheap.
        let mut ema = 0u64;
        for _ in 0..20 {
            ema = ema_step(ema, heavy);
        }

        let mut ema_wrong_ticks = 0usize; // ticks spinning sidecars on cheap work
        let mut cert_wrong_ticks = 0usize;
        for _ in 0..16 {
            ema_scaler.scale(ema, demand); // sees the lagging average
            cert_scaler.scale_certified(cheap, demand); // sees the true cheap cost
            if ema_scaler.active_sidecars() > 0 {
                ema_wrong_ticks += 1;
            }
            if cert_scaler.active_sidecars() > 0 {
                cert_wrong_ticks += 1;
            }
            ema = ema_step(ema, cheap); // workload is now cheap
        }

        assert_eq!(
            cert_wrong_ticks, 0,
            "certified scaler must drop to zero sidecars on cheap certified work"
        );
        assert!(
            ema_wrong_ticks >= 1,
            "EMA scaler should lag and keep sidecars spun up on cheap work after a \
             heavy->cheap switch; measured lag = {ema_wrong_ticks} ticks"
        );
    }
}
